mapper.select:
select a.*, b.bed_id,b.name, c.bed_no,c.room_id, d.room_name from t_leave a inner join t_live b on a.live_id = b.id inner join t_bed c on b.bed_id = c.id inner join t_room d on c.room_id = d.id
and a.status = #{status}
and a.visitor_name like concat('%',#{visitorName},'%')
and b.user_id = #{userId}
and b.name like concat('%',#{name},'%')
order by a.create_time desc limit #{start},#{limit};

select count(a.id) from t_leave a inner join t_live b on a.live_id = b.id inner join t_bed c on b.bed_id = c.id inner join t_room d on c.room_id = d.id
and a.status = #{status}
and a.visitor_name like concat('%',#{visitorName},'%')
and b.user_id = #{userId}
and b.name like concat('%',#{name},'%')
